import React from 'react'
import styled from 'styled-components'
import axios from 'axios'
import Post from './Post'

const PostBox = styled.div`
    background-color: #c0ffee;
    min-width: 100vw;
    display:  flex;
    flex-wrap: wrap;
    gap: 10px;
`

const Posts = ({ posts, updatePostState, user }) => {

    const deletePost= (id) => {
        axios.delete(`http://localhost:8000/bunnybook/posts/${id}`)
        .then(res => {
            console.log(res)
            updatePostState(id)
        })
    }

    return (

    <PostBox>
        { 
          posts.length === 0 ? 'No Post Available' :  (posts.map( post => {
                return <Post key={post._id} post={post} deletePost={deletePost} user={user}/>
            }))
        }
    </PostBox>
  )
}

export default Posts
